VALUES
  ('public-health-specialist-moex-00397', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '健康識能不包括下列何種能力？', '["提供健康資訊", "處理健康資訊", "理解健康資訊", "獲得健康資訊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00398', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關高齡長者、外來移居者或特殊族群影響醫療健康服務系統使用之因子，下列敘述何者錯誤？', '["依據世界衛生組織公布資訊，現今全球超過四億人口無法獲得必要的醫療照護。世界衛生 組織倡議新的「以人為中心的整合性醫療服務框架」，此倡議試圖轉變過去圍繞疾病與醫事 機構設計的醫療健康體系", "不同國家之高齡長者、外來移居者或特殊族群的經濟收入程度，可能影響該國家人民之健 康識能程度以及醫療健康服務系統使用情況", "醫事人員必須改變自身對健康識能的思維模式，從關注「調整體系，因應人們複雜需求」， 轉向為「提升人的技能以滿足整個體系的複雜要求」", "婚姻狀況、生活狀況、社會支持是屬於健康識能的情境因子（situationaldeterminants）；文 化、語言、居住位置是屬於健康識能的社會環境因子（societalandenvironmentaldeterminants）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00399', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '健康識能（healthliteracy）是有關個人與健康資訊互動的能力。完整的健康識能應包含三個層 級的能力，下列何者錯誤？', '["經濟性（economy）識能", "溝通／互動性（communicative/interactive）識能", "批判性（critical）識能", "功能性（functional）識能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00400', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '「醫病共享決策（SharedDecisionMaking,SDM）」－醫療諮詢與醫病溝通，是全球醫療界當 前之共識，下列敘述何者錯誤？', '["醫病共享決策是在現有的實證醫療前提下，做出最佳決策，讓病人在符合自己的期待下得 到更好的醫療結果", "醫病共享決策最重要的是資訊的提供，協助病人與家屬做出不後悔的選擇", "醫病共享決策是1982年美國「以病人為中心」、促進醫病相互尊重與溝通所提出的策略", "醫病共享決策自 2015 年列入我國醫院評鑑基準中，這是一個醫療人員與病人及家屬合作 的過程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00401', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某研究欲探討與使用乳房攝影有關的影響因素，並運用健康信念模式發展問卷，其中有一題 目為「請問您覺得自己得到乳癌的可能性為何？」，此題最有可能是測量下列何者？', '["自覺嚴重度", "自覺利益", "自覺罹患性", "自我效能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00402', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列對於跨理論模式（TranstheoreticalModel,TTM）的敘述，何者錯誤？', '["自我效能（Self-efficacy）是在特定情境下改變問題行為的能力（ability）", "是將多樣不同的行為改變理論，系統性整合不同心理治療領域的理論模式", "行為改變是一個隨著時間演進的過程", "多數高風險族群尚未準備好採取行動，以行動導向的行為改變計畫對他們沒有明顯成效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00403', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '對於計畫行為論（Theory of Planned Behavior, TPB）與理性行為理論（Theory of Reasoned Action,TRA）敘述，何者錯誤？', '["理性行為理論認為，個人對特定行為偏好的行為意圖，會受到個人是否認同的態度及重要 他人是否支持的主觀規範二者或其中之一的影響", "理性行為論較計畫行為論更受學者重視，被認定為較完整的行為意圖模式", "主觀規範（subjectivenorm）乃指個人在採取某一項特定行為時所感受到的社會壓力，亦即 個人知覺到的重要他人（如父母）認為他應否執行該特定行為之壓力", "行為意圖（behavior intention, BI）乃指個人想從事某特定行為之行動傾向與程度，亦即在 行為選擇的決定過程中，個人是否有所行動的心理強度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00404', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某卡車司機在健康檢查後數據呈現有高血壓和高血脂的情況，但被問到其罹患慢性病的機率 時，該司機認為他自己不太可能罹患慢性病。這位卡車司機可能出現了以下何種現象？', '["認知偏誤", "物理偏誤", "樂觀偏誤", "信念偏誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00405', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '根據衛生福利部的臺灣健康不平等報告，城鄉間存在著健康差異，例如發展較為劣勢的地區 相較於發展優勢的地區，孩童交通事故死亡率較高。根據這樣的資訊，某單位因此特別製作 各樣的宣導手冊及短片，在發展較為劣勢的鄉鎮，透過村長及衛生所，發放手冊及播放短片 宣導，使主要照顧者了解如何因應孩童在路上的安全。請問根據社會行銷的要素（Grier & Bryant,2005），此做法是那一項要素？', '["交換", "對象區隔", "競爭", "行銷組合（4P）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00406', 'public-health-specialist', 'public-health-specialist-moex-112-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '政府一系列的禁菸政策，其中提高菸稅以及無菸場所的制定，前述這些作為是利用行為改變 的什麼原理？', '["處罰原理", "類化原理", "逐步養成原理", "飽足原理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:37+00:00", "source_pdf_sha1": "aa70436e61be", "answer_pdf_sha1": "c6cd3f72d4e4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
